mapper.select:
SELECT TRUNK_ID, TRUNK_NAME, TID, SYSNAME, ROADM_CODE , PTPNAME, PORT, OCRTIME, IN_OUT, VALUE_CUR , VALUE_MAX, VALUE_MIN, DIRECTION, ROUTENUM FROM MBA.TB_ROADM_OPTICAL_PERFORMANCE_HIST WHERE 1=1
AND OCRTIME = #{ocrTime} ::timestamp
AND OCRTIME BETWEEN #{fromTime} ::timestamp AND #{toTime} ::timestamp
AND ROUTENUM = #{routeNum}
AND TRUNK_ID = #{trunkId}
AND DIRECTION = #{direction}
ORDER BY TRUNK_ID, DIRECTION, ROUTENUM, IN_OUT

